const body = $json.body || $json;

const forbiddenTerms = [
  'visita técnica',
  'visita tecnica',
  'agendar visita',
  'marcar visita',
  'registrar visita',
  'vistoria'
];

const officialTerm = 'Avaliação Técnica';

function cleanText(value) {
  if (!value || typeof value !== 'string') return value || '';
  let text = value;
  for (const term of forbiddenTerms) {
    const regex = new RegExp(term, 'gi');
    text = text.replace(regex, officialTerm);
  }
  return text.trim();
}

const normalized = {
  origem: body.origem || body.source || 'canal_nao_identificado',
  canal: body.canal || body.channel || 'desconhecido',
  nome: cleanText(body.nome || body.name || ''),
  telefone: String(body.telefone || body.phone || body.whatsapp || '').replace(/\D/g, ''),
  email: String(body.email || '').toLowerCase().trim(),
  bairro: cleanText(body.bairro || body.region || ''),
  mensagem_original: cleanText(body.mensagem || body.message || body.text || ''),
  perfil_cliente: cleanText(body.perfil_cliente || body.tipo_cliente || ''),
  teste: body.teste === true || body.origem === 'TESTE_DL_NEXUS',
  termo_oficial: officialTerm,
  regra_vocabulario: 'PROIBIDO_USAR_VISITA_TECNICA_USAR_AVALIACAO_TECNICA',
  timestamp: new Date().toISOString()
};

return [{ json: normalized }];

const msg = ($json.mensagem_original || '').toLowerCase();

const servicos = {
  seguranca: ['camera', 'câmera', 'cftv', 'controle de acesso', 'facial', 'biometria', 'portaria', 'cerca elétrica', 'cerca eletrica'],
  incendio: ['incêndio', 'incendio', 'alarme de incêndio', 'detector', 'sirene', 'acionador', 'iluminação de emergência'],
  eletrica: ['elétrica', 'eletrica', 'quadro', 'disjuntor', 'painel', 'carga', 'curto', 'iluminação', 'bomba'],
  solar: ['solar', 'fotovoltaico', 'inversor', 'placa solar', 'energia solar', 'híbrido', 'hibrido'],
  automacao: ['automação', 'automacao', 'alexa', 'google assistente', 'portão', 'portao', 'wi-fi', 'bluetooth'],
  commander_nexus: ['cisterna', 'recalque', 'boia', 'bóia', 'nível', 'nivel', 'bomba', 'painel de comando', 'alarme de nível', 'falha de bomba'],
  contrato: ['contrato', 'manutenção preventiva', 'manutencao preventiva', 'sistema recorrente', 'sla', 'relatório mensal']
};

const bloqueioHidraulico = ['vazamento', 'encanamento', 'cano', 'mangueira', 'hidráulica pura', 'hidraulica pura', 'sprinkler hidráulico', 'sprinkler hidraulico'];

let area = 'nao_classificado';
let prioridade = 'media';
let escopo_bloqueado = false;
let motivo_bloqueio = '';

for (const [key, palavras] of Object.entries(servicos)) {
  if (palavras.some(p => msg.includes(p))) {
    area = key;
    break;
  }
}

if (bloqueioHidraulico.some(p => msg.includes(p))) {
  escopo_bloqueado = true;
  motivo_bloqueio = 'Pedido aparenta ser manutenção hidráulica pura. Redirecionar para escopo elétrico, comando, automação, proteção ou monitoramento.';
}

if (['urgente', 'emergência', 'emergencia', 'parou', 'queimou', 'sem energia', 'alarme disparando', 'bomba parada'].some(p => msg.includes(p))) {
  prioridade = 'alta';
}

if (area === 'commander_nexus') {
  prioridade = 'alta';
}

return [{
  json: {
    ...$json,
    area_interesse: area,
    prioridade,
    escopo_bloqueado,
    motivo_bloqueio,
    produto_estrategico: area === 'commander_nexus' ? 'DL Commander Nexus' : null
  }
}];

const j = $json;

let resposta = '';
let proxima_acao = '';

if (j.escopo_bloqueado) {
  resposta = `Olá${j.nome ? ', ' + j.nome : ''}. A DL Soluções atua na parte elétrica, comando, automação, proteção, monitoramento e inteligência preventiva dos sistemas do condomínio. Para intervenção hidráulica pura, o ideal é acionar um profissional hidráulico. Podemos realizar uma Avaliação Técnica da parte elétrica, comando, automação e prevenção de falhas do sistema.`;
  proxima_acao = 'encaminhar_para_avaliacao_escopo_eletrico_automacao';
} else if (j.area_interesse === 'commander_nexus') {
  resposta = `Olá${j.nome ? ', ' + j.nome : ''}. Pelo seu relato, isso pode envolver sistema crítico de bomba, cisterna, recalque, boia, nível ou painel de comando. A solução indicada é uma Avaliação Técnica para verificar a parte elétrica, comando, automação e prevenção de falhas. A DL pode avaliar a aplicação do DL Commander Nexus para monitoramento e controle inteligente do sistema.`;
  proxima_acao = 'acionar_diego_para_dl_commander_nexus';
} else if (j.area_interesse === 'nao_classificado') {
  resposta = `Olá${j.nome ? ', ' + j.nome : ''}. Recebemos sua mensagem. Para direcionar corretamente, por gentileza informe qual sistema precisa de atendimento: segurança eletrônica, elétrica, incêndio, energia solar, automação, bombas/cisterna ou contrato de manutenção.`;
  proxima_acao = 'solicitar_qualificacao';
} else {
  resposta = `Olá${j.nome ? ', ' + j.nome : ''}. Recebemos sua solicitação sobre ${j.area_interesse}. Para avançarmos com segurança, o próximo passo é uma Avaliação Técnica da DL Soluções, onde analisamos o cenário, riscos, infraestrutura e melhor solução para o condomínio.`;
  proxima_acao = 'encaminhar_para_diego';
}

return [{
  json: {
    ...j,
    resposta_aninha: resposta,
    proxima_acao,
    status: 'triado_aninha',
    agente: 'Aninha',
    linguagem_validada: true,
    termo_comercial_obrigatorio: 'Avaliação Técnica'
  }
}];

const text = JSON.stringify($json).toLowerCase();

const proibidos = [
  'visita técnica',
  'visita tecnica',
  'agendar visita',
  'marcar visita',
  'registrar visita',
  'canaleta plástica',
  'canaleta plastica'
];

const encontrados = proibidos.filter(t => text.includes(t));

if (encontrados.length > 0) {
  return [{
    json: {
      ...$json,
      killcritic_status: 'BLOQUEADO',
      termos_proibidos_encontrados: encontrados,
      erro_critico: 'Resposta contém termo proibido ou fora do posicionamento DL.'
    }
  }];
}

return [{
  json: {
    ...$json,
    killcritic_status: 'APROVADO',
    termos_proibidos_encontrados: []
  }
}];
